def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        exp_term = 0
        cos_term = 0
        sin_term = 0
        for j in range(1, 20):
            factor = (0.9 if j % 2 == 0 else 1.1)
            exp_term += factor * np.exp(-j * ratio)
            cos_term += 0.5 * np.cos(j * np.pi * ratio)
            sin_term += 0.3 * np.sin(j * np.pi / (j + 1) * ratio)
            if j % 5 == 0:
                score += (factor * (ratio ** j) / (j + 1))
        score += exp_term + cos_term + sin_term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
            score += (capacity * 0.1)
        elif remaining < 0.08 * capacity:
            score *= 1.7
            score += (capacity * 0.05)
        elif remaining < 0.15 * capacity:
            score *= 1.2
        else:
            score *= 0.6
            score -= (capacity * 0.02)
        mods = [(3, 0.07), (4, 0.03), (6, 0.05), (8, 0.04)]
        mod_adjust = 0
        for mod_val, val in mods:
            if int(capacity) % mod_val == 0:
                mod_adjust += val * (capacity / mod_val)
            else:
                mod_adjust -= (val / 2) * (capacity / (mod_val + 1))
        score -= mod_adjust
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 3 * threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.08 * k
            if k % 2 == 0 and diff < threshold / 2:
                penalty += 0.1 * k
        score += penalty
        if score < 0:
            score = 0
        adjustment_flag = False
        for m in range(1, 5):
            test_val = capacity / m
            if abs(test_val - item) < 0.025 * test_val:
                score *= (1 + 0.07 * m)
                adjustment_flag = True
                if m == 3:
                    score += 0.5
            if adjustment_flag and m == 4:
                score *= 0.95
        if score > capacity / 50:
            reduction_factor = 0.9
            for n in range(1, 4):
                if (capacity + n * item) % (n + 2) == 0:
                    reduction_factor -= 0.05 * n
            score *= max(reduction_factor, 0.7)
        priorities[i] = score
    return priorities
